          .width(44)
          .height(44)
          .borderRadius(Theme.radiusTiny)
          .backgroundColor(Theme.lightGray)
          .justifyContent(FlexAlign.Center)
          .onClick(() => this.goShare(this.dishName.length > 0 ? this.dishName : '今日打卡', '记录美好一餐'))
        }
        .width('100%')
