            Row({ space: 6 }) {
              SvgIcon({ variant: 'share-card', iconSize: 18 })
              Text('生成卡片')
                .fontSize(15)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.textPrimary)
            }
            .id('checkin-share-button')
            .layoutWeight(1)
