                    .fontColor(Theme.warmGray)
                    .margin({ bottom: 6 })
                  Text(c.dishName)
                    .fontSize(16)
                    .fontWeight(FontWeight.Bold)
                    .fontColor(Theme.textPrimary)
                    .margin({ bottom: 8 })
                  Text(this.dateLabel(c))
                    .fontSize(11)
                    .fontColor(Theme.sage)
                    .fontWeight(FontWeight.Medium)
                }
