  }

  private dateLabel(c: Checkin): string {
    const d = new Date(c.createdAt);
    const hh = d.getHours();
    const mm = d.getMinutes();
    const mmStr = mm < 10 ? '0' + mm : '' + mm;
    const hhStr = hh < 10 ? '0' + hh : '' + hh;
    const tk = this.todayKey();
    if (c.dateKey === tk) {
      return '今天 ' + hhStr + ':' + mmStr;
    }
    return c.dateKey.slice(5).replace('-', '/') + ' ' + hhStr + ':' + mmStr;
  }

  private todayKey(): string {
    const d = new Date();
    const y = d.getFullYear();
    const m = d.getMonth() + 1;
    const day = d.getDate();
    const mm = m < 10 ? '0' + m : '' + m;
    const dd = day < 10 ? '0' + day : '' + day;
    return '' + y + '-' + mm + '-' + dd;
  }

  @Builder
  FeatureCard(item: FeatureItem) {
    Column() {
      Row() {
        SvgIcon({ variant: item.icon, iconSize: 24 })
      }
      .width(48)
      .height(48)
      .borderRadius(Theme.radiusTiny)
      .backgroundColor(item.tint)
      .justifyContent(FlexAlign.Center)

      Text(item.title)
        .fontSize(16)
        .fontWeight(FontWeight.Bold)
